parameters.jsCode:
const c = $('Needs Analysis').item.json;
let ai = {};
try {
  const content = ($json.choices && $json.choices[0] && $json.choices[0].message)
    ? $json.choices[0].message.content
    : '{}';
  ai = JSON.parse(content);
} catch (e) {
  ai = {};
}
return {
  Control_ID: c.Control_ID,
  Control_Name: c.Control_Name,
  Current_Status: c.Status || 'Missing - no evidence',
  Gap_Description: ai.gap_description || 'Unable to parse AI gap analysis; manual review required.',
  Risk_Impact: ai.risk_impact || 'Not assessed',
  Remediation: ai.remediation || 'Manual remediation planning required.',
  Priority: ai.priority || 'Medium',
  Timeline: ai.timeline || '90 days',
};
